const e=`{% block sw_category_view %} <sw-card-view class="sw-category-view" position-identifier="sw-category-view" > {% block sw_category_view_language_info %} <sw-language-info :entity-description="placeholder(category, 'name', $t('sw-manufacturer.detail.textHeadline'))" /> {% endblock %} {% block sw_category_view_column_info %} <mt-banner v-if="isCategoryColumn" class="swag-category-view__column-info" variant="info" > <div class="swag-category-view__column-info-header"> {{ $t('sw-category.view.columnInfoHeader') }} </div> <div class="swag-category-view__column-info-content"> {{ $t('sw-category.view.columnInfo') }} </div> </mt-banner> {% endblock %} {% block sw_category_view_tabs %} <sw-tabs v-if="!isLoading" position-identifier="sw-category-view" class="sw-category-detail-page__tabs" > {% block sw_category_view_tabs_general %} <sw-tabs-item class="sw-category-detail__tab-base" :route="{ name: 'sw.category.detail.base' }" :title="$t('sw-category.view.general')" :has-error="swCategoryViewError" > {{ $t('sw-category.view.general') }} </sw-tabs-item> {% endblock %} {% block sw_category_view_tabs_products %} <sw-tabs-item v-show="isPage && !isCustomEntity" class="sw-category-detail__tab-products" :route="{ name: 'sw.category.detail.products' }" :title="$t('sw-category.view.products')" > {{ $t('sw-category.view.products') }} </sw-tabs-item> {% endblock %} <sw-tabs-item v-show="isCustomEntity" class="sw-category-detail__tab-custom-entity" :route="{ name: 'sw.category.detail.customEntity' }" :title="$t('sw-category.view.customEntity')" > {{ $t('sw-category.view.customEntity') }} </sw-tabs-item> {% block sw_category_view_tabs_cms %} <sw-tabs-item v-show="cmsPage || isPage" class="sw-category-detail__tab-cms" :route="{ name: 'sw.category.detail.cms' }" :title="$t('sw-category.view.cms')" > {{ $t('sw-category.view.cms') }} </sw-tabs-item> {% endblock %} {% block sw_category_view_tabs_seo %} <sw-tabs-item v-show="isPage" class="sw-category-detail__tab-seo" :route="{ name: 'sw.category.detail.seo' }" :title="$t('sw-category.view.seo')" > {{ $t('sw-category.view.seo') }} </sw-tabs-item> {% endblock %} </sw-tabs> {% endblock %} {% block sw_category_view_content %} <router-view v-slot="{ Component }" > <component :is="Component" :is-loading="isLoading" /> </router-view> {% endblock %} </sw-card-view> {% endblock %}`,t={"sw.category.view":{category:["name","type"]}},{mapPageErrors:s}=Shopware.Component.getComponentHelper(),o={template:e,inject:["acl"],mixins:["placeholder"],props:{isLoading:{type:Boolean,required:!0,default:!1},type:{type:String,required:!1,default:"page"}},computed:{category(){return Shopware.Store.get("swCategoryDetail").category},isCategoryColumn(){return Shopware.Store.get("swCategoryDetail").isCategoryColumn},cmsPage(){return this.type==="folder"||this.type==="link"?!1:Shopware.Store.get("cmsPage").currentPage},isPage(){return this.type!=="folder"&&this.type!=="link"},isCustomEntity(){return this.type==="custom_entity"},...s(t)}};export{o as default};
